import{_ as r,o as s,c as n,ah as a}from"./chunks/framework.Be4cSgRn.js";const m=JSON.parse('{"title":"Fase 4: Mikrosegmentering & sikkerhedsarkitektur","description":"","frontmatter":{"title":"Fase 4: Mikrosegmentering & sikkerhedsarkitektur","phase":4,"topic":"sikkerhed","personas":["arkitekt","sikkerhed"],"tags":["mikrosegmentering","firewall","deny-by-default","CIS","logning","hændelsesrespons"],"priority":"parallel","dependencies":[1]},"headers":[],"relativePath":"faser/04-mikrosegmentering.md","filePath":"faser/04-mikrosegmentering.md"}'),t={name:"faser/04-mikrosegmentering.md"};function i(l,e,o,k,d,p){return s(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="fase-4-mikrosegmentering-sikkerhedsarkitektur" tabindex="-1">Fase 4: Mikrosegmentering &amp; sikkerhedsarkitektur <a class="header-anchor" href="#fase-4-mikrosegmentering-sikkerhedsarkitektur" aria-label="Permalink to &quot;Fase 4: Mikrosegmentering &amp; sikkerhedsarkitektur&quot;">​</a></h1><div class="phase-meta"><span><strong>Sti:</strong> <span class="parallel-badge">Parallel</span></span><span><strong>Afhænger af:</strong> Fase 1 (netværk)</span><span><strong>Skal være klar inden:</strong> Fase 9</span></div><div class="persona-badges"><span class="persona-badge arkitekt">🏗️ Arkitekt</span><span class="persona-badge sikkerhed">🛡️ Sikkerhedsansvarlig</span></div><p>Det forventes, at sikkerhedsarkitekturen implementeres som en integreret del af platformdesignet — ikke som et efterfølgende lag. Mikrosegmentering er fundamentet for tenant-isolation i en multi-tenant-platform.</p><ul><li><p>Dedikerede netværkszoner pr. tenant med deny-by-default firewall-policies implementeres som standard; al trafik mellem tenants nægtes medmindre eksplicit godkendt.</p></li><li><p>Mikrosegmentering på workload-niveau konfigureres, så lateral bevægelse mellem systemer — selv inden for samme tenant — kræver eksplicit policy-godkendelse.</p></li><li><p>Hærdningsstandarder baseret på anerkendte frameworks (f.eks. CIS Benchmarks) defineres for alle systemtyper og håndhæves via automatiseret compliance-scanning.</p></li><li><p>Centraliseret logning og overvågning med korrelering på tværs af alle infrastrukturlag konfigureres med tenant-specifik filtrering og adgangskontrol.</p></li><li><p>Hændelsesresponsplan med specifikke procedurer for multi-tenant-scenarier dokumenteres og testes før første tenant onboardes.</p></li></ul>',5)])])}const f=r(t,[["render",i]]);export{m as __pageData,f as default};
